import { describe, it, expect } from 'bun:test';
import {
  julianYearsToPicolorenzos,
  EARTH_FORMATION_AGE_YEARS,
  earthFormationAgeGnosticReport,
  earthFormationAgeUncertaintyBracketGnostic,
  JULIAN_YEAR_SECONDS,
} from './earth-chronometry';
import { PICOLORENZO_SECONDS, secondsToPicolorenzos, decomposeGnosticTime } from './math';

describe('Earth chronometry (Gnostic mapping of geochronology input)', () => {
  it('matches π-day picolorenzo definition via Julian years', () => {
    const oneYearPlo = julianYearsToPicolorenzos(1);
    const expected = (365.25 * 86400) / PICOLORENZO_SECONDS;
    expect(oneYearPlo).toBeCloseTo(expected, 10);
    expect(oneYearPlo).toBeCloseTo(365.25 / Math.PI, 10);
  });

  it('maps 4.54 Gyr to ~5.28×10^11 pLo (order-of-magnitude sanity)', () => {
    const pLo = julianYearsToPicolorenzos(EARTH_FORMATION_AGE_YEARS);
    expect(pLo).toBeGreaterThan(5.2e11);
    expect(pLo).toBeLessThan(5.4e11);
  });

  it('earthFormationAgeGnosticReport uses geochronology input and decomposes ladder', () => {
    const r = earthFormationAgeGnosticReport();
    expect(r.epistemicNote).toBe('geochronology_input_not_gnosis_theorem');
    expect(r.formationAgeJulianYears).toBe(EARTH_FORMATION_AGE_YEARS);
    expect(r.gnosticLadder).toEqual(decomposeGnosticTime(r.durationPicolorenzos));
    expect(r.durationNanolorenzos).toBeCloseTo(r.durationPicolorenzos / 1000, 5);
  });

  it('uncertainty bracket is symmetric in years and monotonic in pLo', () => {
    const b = earthFormationAgeUncertaintyBracketGnostic();
    expect(b.lowerYears).toBeLessThan(EARTH_FORMATION_AGE_YEARS);
    expect(b.upperYears).toBeGreaterThan(EARTH_FORMATION_AGE_YEARS);
    expect(b.lowerPLo).toBeLessThan(julianYearsToPicolorenzos(EARTH_FORMATION_AGE_YEARS));
    expect(b.upperPLo).toBeGreaterThan(julianYearsToPicolorenzos(EARTH_FORMATION_AGE_YEARS));
  });

  it('JULIAN_YEAR_SECONDS matches secondsToPicolorenzos round-trip for 1 Gyr', () => {
    const gy = 1e9;
    expect(secondsToPicolorenzos(gy * JULIAN_YEAR_SECONDS)).toBeCloseTo(
      julianYearsToPicolorenzos(gy),
      5
    );
  });
});
